const f = $input.first().json;

// ── Technical Severity (0–10) ──────────────────────────────────
const sevScore = { critical: 10, high: 8, medium: 5, low: 2, informational: 0 };
const technicalSeverity = sevScore[f.severity] ?? 5;

// ── Validation Confidence (0–10) ──────────────────────────────
const valScore = { validated: 10, analyst_reviewed: 7, scanner_only: 4, pending_analyst: 4, likely_false_positive: 1 };
const validationConfidence = valScore[f.validation_status] ?? 4;

// ── Internet Exposure (0–10) ───────────────────────────────────
let internetExposure = 5;
if (f.scope_status === 'in_scope' && f.environment === 'production') internetExposure = 10;
else if (f.environment === 'staging') internetExposure = 6;
else if (f.environment === 'development') internetExposure = 3;
if (f.auth_required) internetExposure = Math.max(2, internetExposure - 3);

// ── Asset Criticality (0–10) ──────────────────────────────────
const critScore = { critical: 10, high: 7, medium: 4, low: 1 };
const assetCriticality = critScore[f.business_criticality] ?? 4;

// ── Data Sensitivity (0–10) ───────────────────────────────────
const sensitiveCategories = ['injection','auth','access_control','crypto','exposure'];
const dataSensitivity = sensitiveCategories.includes(f.category) ? 8 : 4;

// ── Ease of Exploitation (0–10) ───────────────────────────────
const easyExploit = ['xss','injection','config','exposure'];
const hardExploit = ['ssrf','xxe','path_traversal'];
let easeOfExploitation = 5;
if (easyExploit.includes(f.category)) easeOfExploitation = 8;
else if (hardExploit.includes(f.category)) easeOfExploitation = 3;

// ── Recurrence Bonus ──────────────────────────────────────────
const recurrenceBonus = f.is_recurring ? Math.min(4, (f.recurrence_count || 0) * 2) : 0;

// ── Breadth (across assets) ───────────────────────────────────
const breadthBonus = f.occurrence_count > 5 ? 3 : f.occurrence_count > 2 ? 1 : 0;

// ── Auth Boundary Bonus ───────────────────────────────────────
const authBoundaryBonus = (f.auth_required === false && f.category !== 'config') ? 2 : 0;

// ── Composite Score (0–10 scale) ─────────────────────────────
const weighted =
  technicalSeverity   * 0.20 +
  validationConfidence * 0.15 +
  internetExposure    * 0.15 +
  assetCriticality    * 0.15 +
  dataSensitivity     * 0.10 +
  easeOfExploitation  * 0.10;

const reconScore = Math.min(10, Math.max(0,
  weighted + (recurrenceBonus * 0.08) + (breadthBonus * 0.07) + authBoundaryBonus
));

const roundedScore = Math.round(reconScore * 100) / 100;

// ── Priority Bucket ───────────────────────────────────────────
let priorityBucket;
if (roundedScore >= 8.5)      priorityBucket = 'immediate_attention';
else if (roundedScore >= 7.0) priorityBucket = 'high_priority';
else if (roundedScore >= 5.0) priorityBucket = 'medium_priority';
else if (roundedScore >= 3.0) priorityBucket = 'low_priority';
else if (roundedScore >= 1.0) priorityBucket = 'monitor';
else                          priorityBucket = 'likely_false_positive';

// ── Score Explanation ─────────────────────────────────────────
const reasons = [];
if (technicalSeverity >= 8) reasons.push(`High technical severity (${f.severity})`);
if (validationConfidence >= 8) reasons.push('Analyst validated');
if (internetExposure >= 8) reasons.push('Internet-exposed production asset');
if (assetCriticality >= 8) reasons.push(`Critical asset (${f.business_criticality} criticality)`);
if (recurrenceBonus >= 2) reasons.push(`Recurring finding (${f.recurrence_count} prior engagement(s))`);
if (breadthBonus > 0) reasons.push(`Affects ${f.occurrence_count} assets (breadth)`);
if (authBoundaryBonus > 0) reasons.push('No authentication required');
if (validationConfidence <= 4) reasons.push('Confidence capped — pending analyst review');

const scoreExplanation = reasons.length > 0
  ? `Score ${roundedScore}/10 (${priorityBucket.replace(/_/g,' ')}): ${reasons.join('; ')}.`
  : `Score ${roundedScore}/10 (${priorityBucket.replace(/_/g,' ')})`;

const scoreBreakdown = {
  technical_severity: technicalSeverity,
  validation_confidence: validationConfidence,
  internet_exposure: internetExposure,
  asset_criticality: assetCriticality,
  data_sensitivity: dataSensitivity,
  ease_of_exploitation: easeOfExploitation,
  recurrence_bonus: recurrenceBonus,
  breadth_bonus: breadthBonus,
  auth_boundary_bonus: authBoundaryBonus
};

return [{ json: {
  finding_id: f.id,
  recon_score: roundedScore,
  priority_bucket: priorityBucket,
  score_explanation: scoreExplanation,
  score_breakdown: scoreBreakdown,
  severity: f.severity,
  is_immediate: priorityBucket === 'immediate_attention'
} }];
